class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> res = new ArrayList<>();
        for (int i = 1; i <= 9; i++) {
            dfs(i, n - 1, k, res);
        }
        int[] ans = new int[res.size()];
        for (int i = 0; i < res.size(); i++) {
            ans[i] = res.get(i);
        }
        return ans;
    }

    private void dfs(int path, int len, int k, List<Integer> res) {
        if (len == 0) {
            res.add(path);
            return;
        }
        int lastDigit = path % 10;
        if (lastDigit - k >= 0) {
            dfs(path * 10 + lastDigit - k, len - 1, k, res);
        }
        if (lastDigit + k <= 9 && k != 0) {
            dfs(path * 10 + lastDigit + k, len - 1, k, res);
        }
    }
}
